const API_BASE = process.env.NEXT_PUBLIC_API_BASE || 'http://127.0.0.1:8000'

/* ---------------- TOKEN HELPERS ---------------- */

export function getToken(): string | null {
  if (typeof window === 'undefined') return null
  return localStorage.getItem('token')
}

// backward compatibility for AuthContext
export function setTokens(access: string, _refresh?: string): void {
  localStorage.setItem('token', access)
}

export function clearTokens(): void {
  localStorage.removeItem('token')
}


/* ---------------- AUTH ---------------- */

// FastAPI: POST /auth/login?email=&password=
export async function login(email: string, password: string) {
  const url = `${API_BASE}/auth/login`

  const res = await fetch(url, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ email, password }),
  })

  if (!res.ok) {
    throw new Error('Login failed')
  }

  const data = await res.json()
  // backend returns { access_token }
  setTokens(data.access_token)
  return data
}

export function logout() {
  clearTokens()
}

/* ---------------- CHAT ---------------- */

// PUBLIC = without token
export async function askPublic(message: string) {
  const res = await fetch(`${API_BASE}/chat`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      message,
      token: null,
    }),
  })

  if (!res.ok) {
    const err = await res.text()
    throw new Error(err)
  }

  return res.json()
}

// PRIVATE = with JWT token
export async function askPrivate(message: string) {
  const token = getToken()

  if (!token) {
    throw new Error('Not authenticated')
  }

  const res = await fetch(`${API_BASE}/chat`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      message,
      token,
    }),
  })

  if (!res.ok) {
    const err = await res.text()
    throw new Error(err)
  }

  return res.json()
}

/* ---------------- DOCUMENT UPLOAD ---------------- */

// FastAPI: POST /documents/upload?user=
export async function uploadTempDoc(file: File, userEmail = 'guest') {
  const API_BASE =
    process.env.NEXT_PUBLIC_API_BASE || 'http://127.0.0.1:8000'

  const formData = new FormData()
  formData.append('file', file)

  // send `user` as a form field to match backend expecting Form(...)
  formData.append('user', userEmail)

  const res = await fetch(`${API_BASE}/documents/upload`, {
    method: 'POST',
    body: formData,
  })

  if (!res.ok) {
    throw new Error(await res.text())
  }

  return res.json()
}

const ACADEMIC_KEYWORDS = [
  'unit','syllabus','explain','derivation','theorem','numerical',
  'dsa','os','dbms','data structure','algorithm','operating system',
  'database','computer network','cn','oops','java','python','c++',
  'programming','code','array','function','exam','notes'
]

export function isAcademicQuery(query: string): boolean {
  const q = query.toLowerCase()
  return ACADEMIC_KEYWORDS.some(k => q.includes(k))
}

